+/// Emit bytecode to load a resolved column reference into a register.
+#[allow(clippy::cast_possible_truncation, clippy::cast_possible_wrap)]
+fn emit_resolved_column(
+    b: &mut ProgramBuilder,
+    resolved: &SortKeySource,
+    cursor: i32,
+    reg: i32,
+    scan: &ScanCtx<'_>,
